resource "aws_route53_query_log" "example" {
  hosted_zone_id = aws_route53_zone.primary.zone_id
  cloud_watch_logs_configuration {
    cloud_watch_logs_role_arn = aws_iam_role.route53_query_logging.arn
    log_group_arn = aws_cloudwatch_log_group.r53_query.name
    enable_logging = true
  }
}

resource "aws_cloudwatch_log_group" "r53_query" {
  name              = "/aws/route53"
  retention_in_days = 7
}

resource "aws_iam_role" "route53_query_logging" {
  name = "route53-query-logging-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = "sts:AssumeRole"
        Effect    = "Allow"
        Principal = {
          Service = "logs.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_policy" "route53_query_logging_policy" {
  name   = "route53-query-logging-policy"
  description = "Allows Route 53 to write logs to CloudWatch Logs."
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "logs:PutLogEvents"
        Effect   = "Allow"
        Resource = [
          "arn:aws:logs:*:*:/aws/route53/*"
        ]
        Condition = {
          StringEquals = {
            "aws:logs:logGroupName" = "/aws/route53"
            "aws:logs:logStreamName" = "QueryLogStream"
          }
        }
      },
    ]
  })
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name = "aws-route53-query-log-group"
  retention_in_days = 30
}

resource "aws_route53_query_log_config" "example" {
  log_destination_configs = [
    aws_cloudwatch_log_group.aws_route53_example_com.name
  ]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_route53_zone" "primary" {
  name = "example53.com"
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/${aws_route53_zone.primary.name}"
  retention_in_days = 30
}

# Example CloudWatch log resource policy to allow Route53 to write logs
# to any log group under /aws/route53/*

data "aws_iam_policy_document" "route53-query-logging-policy" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["arn:aws:logs:*:*:log-group:/aws/route53/*"]

    principals {
      identifiers = ["route53.amazonaws.com"]
      type        = "Service"
    }
  }
}

resource "aws_cloudwatch_log_resource_policy" "route53-query-logging-policy" {
  policy_document = data.aws_iam_policy_document.route53-query-logging-policy.json
  policy_name     = "route53-query-logging-policy"
}

resource "aws_route53_query_log" "example_com" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53-query-logging-policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}

response:
To set up Route 53 query logging with a CloudWatch Logs stream and publish log events using a CloudWatch Logs resource policy, you can use the following Terraform configuration:

```hcl
resource "aws_route53_query_log" "example" {
  hosted_zone_id = aws_route53_zone.primary.zone_id
  cloud_watch_logs_configuration {
    cloud_watch_logs_role_arn = aws_iam_role.route53_query_logging.arn
    log_group_arn = aws_cloudwatch_log_group.r53_query.name
    enable_logging = true
  }
}

resource "aws_cloudwatch_log_group" "r53_query" {
  name              = "/aws/route53"
  retention_in_days = 7
}

resource "aws_iam_role" "route53_query_logging" {
  name = "route53-query-logging-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = "sts:AssumeRole"
        Effect    = "Allow"
        Principal = {
          Service = "logs.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_policy" "route53_query_logging_policy" {
  name   = "route53-query-logging-policy"
  description = "Allows Route 53 to write logs to CloudWatch Logs."
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "logs:PutLogEvents"
        Effect   = "Allow"
        Resource = [
          "arn:aws:logs:*:*:/aws/route53/*"
        ]
        Condition = {
          StringEquals = {
            "aws:logs:logGroupName" = "/aws/route53"
            "aws:logs:logStreamName" = "QueryLogStream"
          }
        }
      },
    ]
  })
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name = "aws-route53-query-log-group"
  retention_in_days = 30
}

resource "aws_route53_query_log_config" "example" {
  log_destination_configs = [
    aws_cloudwatch_log_group.aws_route53_example_com.name
  ]
}
```

This Terraform configuration establishes Route 53 query logging, creates the necessary CloudWatch Logs resource, and sets up a resource policy for logs management.

