  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_db_instance" "primary" {
  identifier = "primary"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "your_password_here"
  skip_final_snapshot  = true
  backup_retention_period  = 7
}

resource "aws_db_instance" "replica_1" {
  replicate_source_db  = aws_db_instance.primary.identifier
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-1"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_2" {
  replicate_source_db  = aws_db_instance.primary.identifier
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-2"
  skip_final_snapshot  = true
}


# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example53.com"
}


# Route53 Records for each RDS Read Replica with a Weighted Routing Policy
resource "aws_route53_record" "replica_1_cname" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica1.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_1.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 10
  }
  set_identifier = "replica-1-record"
}

resource "aws_route53_record" "replica_2_cname" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica2.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_2.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 20
  }
  set_identifier = "replica-2-record"
}

response:
Below is the Terraform configuration using HCL to set up a weighted DNS routing configuration with Route 53, distributing traffic between two read-replica database instances:

```hcl
provider "aws" {
  region = "us-west-2"  # Feel free to adjust region as needed
}

resource "aws_db_instance" "primary" {
  identifier     = "primary"
  instance_class = "db.t2.small"
}

resource "aws_db_instance" "replica1" {
  identifier     = "replica-1"
  instance_class = "db.t2.small"
}

resource "aws_db_instance" "replica2" {
  identifier     = "replica-2"
  instance_class = "db.t2.small"
}

resource "aws_route53_zone" "main" {
  name = "example.com"
}

resource "aws_route53_record" "dns_record_primary" {
  zone_id     = aws_route53_zone.main.id
  name        = "primary.example.com"
  type        = "CNAME"
  ttl         = "60"
  records     = ["primary"]
}

resource "aws_route53_record" "dns_record_replica1" {
  zone_id   = aws_route53_zone.main.id
  name      = "replica-1.example.com"
  type      = "CNAME"
  ttl       = "60"
  weighted_routing_policy {
    weight = 100
  }
  records   = ["replica-1"]
}

resource "aws_route53_record" "dns_record_replica2" {
  zone_id   = aws_route53_zone.main.id
  name      = "replica-2.example.com"
  type      = "CNAME"
  ttl       = "60"
  weighted_routing_policy {
    weight = 50
  }
  records   = ["replica-2"]
}

resource "aws_route53_record" "dns_record_database" {
  zone_id   = aws_route53_zone.main.id
  name      = "db.example.com"
  type      = "A"   # Adjust based on the specific record type needed
  ttl       = "60"

  records = [
    aws_db_instance.replica1.address,
    aws_db_instance.replica2.address
  ]
  set_identifier = "db.example.com"
}
```

In this configuration, the Route 53 zone is named "main" and contains DNS records for the primary and replica instances with weights assigned to distribute traffic between the replicas. Adjust the identifiers and zones as required for your specific setup, including any placeholders or shortcuts for resource types or attributes. Adjust the weights according to your load balancing strategy and set the record type appropriately based on your use-case within AWS RDS.

