provider "aws" {
  region = "us-west-2"
}

variable "blue_env_domain_name" {
  description = "The canonical domain name for the Blue Elastic Beanstalk environment."
  default     = "blue.example.com"
}

variable "green_env_domain_name" {
  description = "The canonical domain name for the Green Elastic Beanstalk environment."
  default     = "green.example.com"
}

resource "aws_route53_zone" "main" {
  name = "example.com"
}

resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.main.zone_id
  name    = var.blue_env_domain_name
  type    = "CNAME"
  ttl     = "60"
  records = ["blue-env.elasticbeanstalk.us-west-2.amazonaws.com"]
}

resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.main.zone_id
  name    = var.green_env_domain_name
  type    = "CNAME"
  ttl     = "60"
  records = ["green-env.elasticbeanstalk.us-west-2.amazonaws.com"]
}

resource "aws_route53_record" "weighted" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"

  weighted_routing_policy {
    weight = 50
  }

  set_identifier = "blue"

  records = ["blue-env.elasticbeanstalk.us-west-2.amazonaws.com"]
}

resource "aws_route53_record" "weighted_green" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"

  weighted_routing_policy {
    weight = 50
  }

  set_identifier = "green"

  records = ["green-env.elasticbeanstalk.us-west-2.amazonaws.com"]
}

