To set up Elastic Beanstalk production and staging environments with their own RDS DB instances using Terraform, you need to create configurations for both environments and their respective RDS instances. Below is the Terraform configuration for your requirements:

```hcl
provider "aws" {
  region = "us-west-2" # Adjust the region if necessary
}

resource "aws_elastic_beanstalk_environment" "prod_environment" {
  name                = "prod-env"
  application         = "your_app_name"
  solution_stack_name = "64bit Amazon Linux 2018.03 v2.9.2 running Python 3.6"

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentName"
    value     = "prod"
  }

  setting {
    namespace = "aws:elasticbeanstalk:cloudwatch:logs:cloudwatch-bus"
    name      = "Enabled"
    value     = true
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "WHLBSBASDBProd"
    value     = true
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDSInstanceProfile"
    value     = "eb_ec2_profile" // Assuming the instance profile is defined elsewhere in your Terraform configuration
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = "prod_db"
  }
}

resource "aws_rds_instance" "prod_db" {
  identifier           = "prod_db"
  allocated_storage    = 20
  instance_class       = "db.t3.micro"
  engine               = "mysql"
  username             = "foo"
  password             = "your_produce_db_password"
  skip_final_snapshot = true
}

resource "aws_elastic_beanstalk_environment" "staging_environment" {
  name                = "staging-env"
  application         = "your_app_name"
  solution_stack_name = "64bit Amazon Linux 2018.03 v2.9.2 running Python 3.6"

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentName"
    value     = "staging"
  }

  setting {
    namespace = "aws:elasticbeanstalk:cloudwatch:logs:cloudwatch-bus"
    name      = "Enabled"
    value     = true
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "WHLBSBASDBStaging"
    value     = true
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDSInstanceProfile"
    value     = "eb_ec2_profile"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = "staging_db"
  }
}

resource "aws_rds_instance" "staging_db" {
  identifier           = "staging_db"
  allocated_storage    = 20
  instance_class       = "db.t3.micro"
  engine              = "mysql"
  username            = "foo"
  password            = "your_staging_db_password"
  skip_final_snapshot = true
}
```

Make sure to replace placeholders such as `"your_app_name"`, `"your_produce_db_password"`, and `"your_staging_db_password"` with your actual application name and credentials. Ensure the `eb_ec2_profile` exists beforehand or is defined outside this configuration. Adjust the regions and solution stack according to your needs.

