To set up a blue-green deployment using AWS Elastic Beanstalk with an RDS database, you'll need to define the environments and manage the RDS snapshot. Below is the Terraform configuration to achieve this task:

```hcl
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "my-app-blue"
  application         = aws_elastic_beanstalk_application.example.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.6 running PHP 7.4"
  tier               = "WebServer"
  version_label      = "Version 1"

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "RDS"
  }

  instance_profile    = "ec2_eb_profile1"
}

resource "aws_elastic_beanstalk_environment" "green" {
  name                = "my-app-green"
  application         = aws_elastic_beanstalk_application.example.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.0 running Go 1"
  tier               = "WebServer"
  version_label       = "Version 2"

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "RDS"
  }

  instance_profile    = "ec2_eb_profile1"
}

resource "aws_rds_cluster" "example" {
  cluster_identifier     = "my-cluster"
  engine                = "mysql"
  database_name        = "my_db"
}

resource "aws_rds_cluster_snapshot" "example_snapshot" {
  cluster_identifier    = aws_rds_cluster.example.cluster_identifier
  db_cluster_snapshot_identifier = "my_db_snapshot"
}

resource "aws_periodic_scheduled_task" "schedule_task" {
  task_identifier = "my_periodic_task"
  frequency = 1
}

resource "aws_elastic_beanstalk_application" "example" {
  name = "MyApp"
  description = "Application for blue-green deployment"
}
```

This configuration sets up two Elastic Beanstalk environments — one for blue and another for green deployment — and creates a snapshot of the existing RDS database named "my_db". The settings link the RDS instance type setting for Elastic Beanstalk, and the RDS name is specified directly. Note that a separate task could be defined to trigger EC2 deployments or database updates based on the blue-green deployment strategy.

