resource "aws_autoscaling_group" "eb_asg" {
  name                      = "eb-asg"
  launch_configuration      = aws_launch_configuration.eb_config.id
  min_size                  = 1
  max_size                  = 3
  health_check_type         = "EC2"
  vpc_zone_identifier       = ["subnet-0bb1c79de3EXAMPLE"] # Replace with actual subnet IDs

  tag {
    key                 = "Name"
    value               = "eb-instance"
    propagate_at_launch = true
  }
}

resource "aws_cloudwatch_metric_alarm" "cpu_high" {
  alarm_name          = "cpu_high"
  comparison_operator = "GreaterThanOrEqualToThreshold"
  evaluation_periods  = "1"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = "300"
  statistic           = "Average"
  threshold           = "70"
  alarm_description   = "Trigger autoscaling when CPU exceeds 70%"

  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.eb_asg.name
  }

  alarm_actions = [aws_autoscaling_policy.cpu_scale_up.arn]
  ok_actions    = [aws_autoscaling_policy.cpu_scale_down.arn]
}

resource "aws_cloudwatch_metric_alarm" "cpu_low" {
  alarm_name          = "cpu_low"
  comparison_operator = "LessThanOrEqualToThreshold"
  evaluation_periods  = "1"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = "300"
  statistic           = "Average"
  threshold           = "30"
  alarm_description   = "Trigger autoscaling when CPU falls below 30%"

  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.eb_asg.name
  }

  alarm_actions = [aws_autoscaling_policy.cpu_scale_down.arn]
  ok_actions    = [aws_autoscaling_policy.cpu_scale_up.arn]
}

resource "aws_elastic_beanstalk_environment" "eb_env" {
  name                = "my-eb-env"
  application         = "my-eb-app"               # Assume the application is already created
  solution_stack_name = "64bit Amazon Linux 2 v3.4.3 running Python 3.8" # Adjust as needed
  option_settings {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "eb_ec2_profile"
  }
  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = aws_db_instance.my_db.id
  }
  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBUser"
    value     = aws_db_instance.my_db.username
  }
  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBPassword"
    value     = random_password.db.result
  }
  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBName"
    value     = aws_db_instance.my_db.db_name
  }
}
```

This configuration sets up an AWS Elastic Beanstalk environment with an attached RDS instance and uses Auto Scaling based on CPU utilization. Ensure the AMI ID, subnet IDs, and other specific values are adjusted according to your AWS setup.

