```hcl
resource "random_id" "eb_suffix" {
  byte_length = 8
}

resource "random_pet" "instance_id" {
  length = 2
}

resource "aws_elastic_beanstalk_application" "example_app" {
  name        = "my-app-${random_id.eb_suffix.hex}"
  description = "Scaffold for an AWS Elastic Beanstalk application"
}

resource "aws_elastic_beanstalk_environment" "example_env" {
  application_name = aws_elastic_beanstalk_application.example_app.name
  solution_stack_name = "64bit Amazon Linux 2018.03 v2.9.6 running PHP 7.2"
  environment_name = "env-${random_pet.instance_id.id}"
  tier {
    name   = "WebServer"
    type   = "Standard"
  }
}
```

