To define an AWS CodeBuild project resource with a sample IAM role, environment variables, multiple secondary source repositories, and secondary build artifacts in Terraform, you can use the following HCL configuration:

```hcl
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild_role"

  assume_role_policy {
    statement = {
      actions = ["sts:AssumeRole"],
      principals = {
        type        = "Service"
        identifiers = ["codebuild.amazonaws.com"]
      },
      effect     = "Allow"
    }
}

resource "aws_codebuild_project" "codebuild_project" {
  name           = "example-codebuild-project"
  description    = "A Terraform-defined CodeBuild project"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image         = "aws/codebuild/standard:4.0"
    type          = "LINUX"
  }

  source {
    type = "GITHUB"
    location = "https://github.com/user/example-repo"
  }

  secondary_source {
    location = "https://github.com/second-user/second-repo"
    source_reference = {
      repository = "branch"
      type      = "branch"
      location  = "main"
    }
  }

  secondary_source {
    location = "git://second-location"
    source_reference = {
      repository = "commit"
      type      = "commit"
      location  = "abcdef123456"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "example-codebuild-log-group"
      status      = "ENABLED"
    }
  }

  environment_variables {
    key          = "MY_ENV_VAR"
    plaintext    = "example"
  }

  secondary_artifacts {
    location = "build-output/"
    reports {
      files = ["build-output.txt"]
      prefix = ""
      suffix = ""
      file_types = ["PLAIN_TEXT"]
    }
  }
}
```

In this configuration:

- A sample IAM role `codebuild_role` is created to allow AWS CodeBuild to assume it.
- The `aws_codebuild_project` resource defines a CodeBuild project, including multiple secondary source repositories and artifacts.
- Environment variables and logging configurations are included to demonstrate setting environment variables and specifying logging options.

