```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_lex_bot" "pizza_order_bot" {
  name           = "childrens-pizza-order-bot"
  role_arn       = "arn:aws:iam::123456789012:role/service-role/AmazonLexFullAccess"
  description    = "A bot to help children place pizza orders"
  checksum       = filebase64sha256("init-bucket.sl")
  locale         = "en-US"
  child_directed = true
}

resource "aws_lex_intent" "order_pizza" {
  name          = "OrderPizza"
  checksum      = filebase64sha256("intent-order-pizza.sl")
  bot_version   = aws_lex_bot.childrens_pizza_order_bot.version
  fulfillment_activity {
    type = "ReturnIntent"
  }
}

resource "aws_lex_slot_type" "toppings" {
  name = "Toppings"
  enumeration {
    value = "mushrooms"
  }
  enumeration {
    value = "peppers"
  }
  enumeration {
    value = "onions"
  }
}

resource "aws_lex_slot_type" "sizes" {
  name = "Sizes"
  enumeration {
    value = "small"
  }
  enumeration {
    value = "medium"
  }
  enumeration {
    value = "large"
  }
}

resource "aws_lex_slot_type" "flavors" {
  name = "Flavors"
  enumeration {
    value = "cheese"
  }
  enumeration {
    value = "pepperoni"
  }
  enumeration {
    value = "sausage"
  }
}
```

**Notes:**
- Replace `"123456789012"` in `role_arn` with your actual AWS account ID.
- For this example, Lex's resource specification (`checksum`) links to locally stored state files for the bot (`init-bucket.sl`) and the intent (`intent-order-pizza.sl`). Ensure these files are properly set up with your Lex bot configurations.
- Slot types are provided for toppings, sizes, and flavors typical of a pizza ordering scenario tailored for children.
- Ensure the attached IAM role grants full access to Lex for this bot to function correctly.

