data "aws_iam_policy_document" "authorise_lambda" {
  statement {
    actions = ["lambda:InvokeFunction"]
    resources = ["arn:aws:lambda:*:*:function:pizza-order"]
    principals {
      type        = "Service"
      identifiers = ["lex.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "lambda_lex_role" {
  name = "lambda-lex-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "lambda.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    },
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "lex.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "lambda_policy" {
  name   = "lambda-lex-policy"
  role   = aws_iam_role.lambda_lex_role.id
  policy = data.aws_iam_policy_document.authorise_lambda.json
}

resource "aws_lambda_function" "pizza_order_lambda" {
  function_name = "pizza-order"
  handler       = "index.handler"
  runtime       = "nodejs14.x"
  filename      = "pizza_order_lambda_function.zip"

  role = aws_iam_role.lambda_lex_role.arn
}

resource "aws_lex_bot" "pizza_bot" {
  name      = "PizzaOrderBot"
  child_directed = false 
  role_arn = aws_iam_role.lambda_lex_role.arn

  locale = "en-US"

  intents {
    name                = "OrderPizza"
    confirmation_prompt = {
      max_attempts = 2
    }
    rejection_statement {
      message = "Ok, maybe next time then!"
    }
    fulfillment_activity {
      type = "CodeHook"
      code_hooks {
        uri            = aws_lambda_function.pizza_order_lambda.invoke_arn
        http_method    = "POST"
        message_version = "1.0"
      }
    }
  }
}

