Here's a Terraform configuration for creating a Kinesis Data Firehose delivery stream that sends data to an OpenSearch destination in AWS. This configuration uses HCL within a single Markdown code block, as requested:

```hcl
resource "aws_kinesis_firehose_delivery_stream" "example" {
  name                        = "example-delivery-stream"
  destination_arn            = aws_opensearch_domain.example.arn
  kinesis_data_source_arn    = aws_kinesis_stream.example.arn
  s3_destination {
    role_arn              = aws_iam_role.example.arn
    bucket_arn            = aws_s3_bucket.example.arn
  }
  format                    = "JSON" // Example format option
}

resource "aws_kinesis_stream" "example" {
  name_prefix              = "example-stream"
}

resource "aws_opensearch_domain" "example" {
  domain_name              = "example-domain"
}

resource "aws_s3_bucket" "example" {
  bucket = "examplebucket"
}

resource "aws_iam_role" "example" {
  name                 = "example-role"
  assume_role_policy  {
    version              = "2012-10-17"
    statement {
      effect              = "Allow"
      principals {
        type              = "Service"
        identifiers      = ["firehose.amazonaws.com"]
      }
      actions             = ["sts:AssumeRole"]
    }
  }
}
```

This configuration creates a Kinesis Data Firehose delivery stream targeting an OpenSearch domain, along with the necessary Kinesis stream, OpenSearch domain, S3 bucket, and IAM role resources. The IAM role assumes policies to allow Firehose to access the bucket. Please adjust the names and ARNs according to your resources and setup.

