resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name        = "firehose_delivery_policy"
  description = "Allows writing streaming data to Splunk via HTTP"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetBucketLayout",
          "s3:ListBucket",
          "s3:GetObject",
          "s3:PutObject"
        ],
        Effect = "Allow",
        Resource = "arn:aws:s3:::my-bucket/*"
      },
      {
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogStream"
        ],
        Effect = "Allow",
        Resource = "arn:aws:logs:us-east-1:123456789012:log-group:firehose-log-group:*"
      },
      {
        Action = [
          "firehose:CreateDeliveryStream",
          "firehose:DeleteDeliveryStream",
          "firehose:UpdateDestination",
          "firehose:PutRecord",
          "firehose:PutRecordBatch"
        ],
        Effect = "Allow",
        Resource = "*"
      },
      {
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey"
        ],
        Effect = "Allow",
        Resource = "arn:aws:kms:us-east-1:123456789012:key/my-key"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attachment" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_kinesis_firehose_delivery_stream" "splunk_firehose" {
  name        = "splunk-firehose"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = "arn:aws:s3:::my-bucket"

    buffer_size        = 10
    buffer_interval    = 300

    cloudwatch_logging_options {
      enabled = true
      log_group_name = "firehose_log_group"
      log_stream_name = "firehose_log_stream"
    }

    s3_backup_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = "arn:aws:s3:::my-backup-bucket"

      buffer_size        = 10
      buffer_interval    = 900
    }
  }

  processor {
    type = "Lambda"
    parameters = {
      ParameterName  = "LambdaArn"
      ParameterValue = "arn:aws:lambda:us-east-1:123456789012:function:my-firehose-processor"
    }
  }

  s3_backup_mode = "FailedTopicsOnly"
}

