  }
}

resource "local_file" "kubeconfig" {
  content     = <<EOF
${file("${path.root}/local/${var.cluster_name}-kubeconfig.yaml", "data")}
  ${file("${path.root}/get-kubeconfig.sh ${var.cluster_name} >> ${path.cwd}/kubeconfig.yaml"}
  ${file("${path.root}/unset-kubeconfig.sh >> /dev/null"}
  EOF
  provisioner "local-exec" {
    command = "${file("${path.root}/make-kubeconfig.sh ${var.cluster_name)}"
  }
  provisioner "local-exec" {
    when = "destroy"
    command = "${file("${path.root}/make-kubeconfig.sh ${var.cluster_name)}"
  }
}

