        Condition = {
          StringEquals = {
            "sts:ExternalId": aws_eks_cluster.example.identity[0].oidc[0].issuer
          }
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eks_fargate_pod_execution_policy_attachment" {
  role       = aws_iam_role.eks_fargate_pod_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
}

resource "aws_eks_cluster" "example" {
  name     = "example"
  role_arn = aws_iam_role.eks_cluster_execution_role.arn

  vpc_config {
    subnet_ids = [
      "subnet-12345678",  # Replace with actual subnets
      "subnet-87654321"
    ]
  }

  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy_attachment,
  ]
}

resource "aws_eks_fargate_profile" "example" {
  cluster_name           = aws_eks_cluster.example.name
  fargate_profile_name   = "example-fargate-profile"
  pod_execution_role_arn = aws_iam_role.eks_fargate_pod_execution_role.arn

  subnet_ids = [
    "subnet-12345678",  # Replace with actual subnets
    "subnet-87654321"
  ]

  selector {
    namespace = "kube-system"
  }
}

locals {
  cluster_name = aws_eks_cluster.example.name
  kubectl_config = <<EOF
apiVersion: v1
clusters:
- cluster:
    certificate-authority-data: ${aws_eks_cluster.example.certificate_authority[0].data}
    server: https://${aws_eks_cluster.example.endpoint}
  name: ${local.cluster_name}
contexts:
- context:
    cluster: ${local.cluster_name}
    user: ${local.cluster_name}
  name: ${local.cluster_name}
current-context: ${local.cluster_name}
kind: Config
preferences: {}
users:
- name: ${local.cluster_name}
  user:
    exec:
      apiVersion: client.authentication.k8s.io/v1alpha1
      command: aws-eks
      args:
        - get-token
        - --cluster-name
        - ${aws_eks_cluster.example.name}
EOF
}

resource "null_resource" "patch_coredns" {
  triggers = {
    cluster_endpoint = aws_eks_cluster.example.endpoint
  }

  provisioner "local-exec" {
    command = "echo '${local.kubectl_config}' > kubeconfig.yaml && kubectl --kubeconfig=kubeconfig.yaml patch deployment coredns -n kube-system --type=json -p='[ {"op": "add", "path": "/spec/template/spec","value": {"serviceAccountName": "coredns", "nodeSelector": {"aws:ecs:containerInstanceIdentity" : "${var.aws_ecs_container_instance_identity}" }}} ]'"
  }

  depends_on = [aws_eks_fargate_profile.example]
}

