  vpc_id      = aws_vpc.main.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_iam_role" "example-cluster" {
  name = "eks-cluster-role"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.example-cluster.name
}

resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.example-cluster.name
}

resource "aws_eks_cluster" "example" {
  name     = "example"
  role_arn = aws_iam_role.example-cluster.arn

  vpc_config {
    subnet_ids = [ aws_subnet.test_eks_1.id, aws_subnet.test_eks_2.id ]
  }
}

resource "aws_iam_role" "example-group" {
  name = "eks-cluster-group-role"

  assume_role_policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": ["eks.amazonaws.com", "ec2.amazonaws.com"]
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
POLICY
}

resource "aws_iam_role_policy_attachment" "example-AmazonEKSWorkerNodePolicy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSWorkerNodePolicy"
  role       = aws_iam_role.example-group.name
}

resource "aws_iam_role_policy_attachment" "example-AmazonEKS_CNI_Policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKS_CNI_Policy"
  role       = aws_iam_role.example-group.name
}

resource "aws_iam_role_policy_attachment" "example-AmazonEC2ContainerRegistryReadOnly" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
  role       = aws_iam_role.example-group.name
}

resource "aws_eks_node_group" "example" {
  cluster_name    = aws_eks_cluster.example.name
  node_group_name = "example"
  node_role_arn   = aws_iam_role.example-group.arn
  subnet_ids      = [ aws_subnet.test_eks_1.id, aws_subnet.test_eks_2.id ]

  scaling_config {
    desired_size = 1
    max_size     = 2
    min_size     = 1
  }

  update_config {
    max_unavailable = 1
  }

  # Ensure that IAM Role permissions are created before and deleted after EKS Node Group handling.
  # Otherwise, EKS will not be able to properly delete EC2 Instances and Elastic Network Interfaces.
  depends_on = [
    aws_iam_role_policy_attachment.example-AmazonEKSWorkerNodePolicy,
    aws_iam_role_policy_attachment.example-AmazonEKS_CNI_Policy,
    aws_iam_role_policy_attachment.example-AmazonEC2ContainerRegistryReadOnly,
  ]
}

response:
Here's a Terraform configuration that meets your requirements for an AWS EKS node group named "example". It sets up the node group associated with an EKS cluster named "example" and includes IAM role attachments to ensure correct permissions for lifecycle operations. Also, it configures the scaling behavior for the node group and specifies update behavior.

```hcl
resource "aws_iam_role" "example_iam_node_role" {
  name = "example-IAM-NodeRole"

  assume_role_policy {
    policy = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Effect = "Allow"
          Principal = {
            Service = "eks.amazonaws.com"
          }
          Action = "sts:AssumeRole"
        },
      ]
    })
}

data "aws_iam_policy_document" "example_worker_node_policy" {
  statement {
    actions     = ["eks:NodegroupsAccess"]
    resources   = ["*"]
    effect     = "Allow"
  }
}

resource "aws_iam_role_policy_attachment" "example_worker_node_policy_attachment" {
  role       = aws_iam_role.example_iam_node_role.name
  policy_arn = aws_iam_policy.example_worker_node_policy.ank
}

resource "aws_iam_policy" "example_worker_node_policy" {
  name        = "example-worker-node-policy"
  policy      = data.aws_iam_policy_document.example_worker_node_policy.json
}

resource "aws_iam_policy_document" "example_eni_policy" {
  statement {
    actions     = ["ec2:DescribeNetworkInterfaces", "ec2:CreateNetworkInterface", "ec2:DeleteNetworkInterface", "ec2:DetachNetworkInterface"]
    resources = ["*"]
    effect = "Allow"
  }
}

resource "aws_iam_role_policy_attachment" "example_eni_policy_attachment" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKS_CNI_Policy"
  role = aws_iam_role.example_iam_node_role.name
}

resource "aws_iam_role_policy_attachment" "example_ecr_policy_attachment" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
  role = aws_iam_role.example_iam_node_role.name
}

resource "aws_eks_node_group" "example" {
  cluster_name = "example"
  node_group_name = "example"
  node_role_arn = aws_iam_role.example_iam_node_role.arn
  subnet_ids     = ["subnet-1234567890abcdef0", "subnet-0987654321abcdef0"] // Specify IDs of your subnets

  scaling_config {
    desired_size = 1
    max_size     = 2
    min_size     = 1
    }

  update_config {
    max_unavailable = 1
  }

  depends_on = [aws_iam_role_policy_attachment.example_worker_node_policy_attachment, aws_iam_role_policy_attachment.example_eni_policy_attachment, aws_iam_role_policy_attachment.example_ecr_policy_attachment]
}
```

In this configuration:
- The `aws_iam_role` resource and its associated policy are defined to ensure the node group can function.
- Policy attachments are made to the IAM role to provide necessary permissions for network interfaces and container registry access.
- The node group is set up with a `scaling_config` and `update_config` for managing availability and update behavior.
- `depends_on` ensures that the IAM policies are attached properly before the node group resources are applied.

