```hcl
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "random_pet" "bucket_name" {
  length = 2
}

resource "aws_s3_bucket" "my_bucket" {
  bucket = "my-bucket-${random_pet.bucket_name.result}"
  acl    = "private"
  force_destroy = true
}

