resource "aws_s3_bucket" "wellcome_collection_platform_infra" {
  bucket = "wellcomecollection-platform-infra"

  lifecycle_rule {
    enabled = true

    abort_incomplete_multipart_upload {
      days_after_initiation = 7
      prefix             = "tmp/"
      status             = "completed"
    }

    id                = "wellcome_collection_platform_infra_lifecycle_rule"
    prefix            = "tmp/"
    enabled          = true
    expiration {
      days           = 30
    }
    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }

  versioning {
    enabled = true

    noncurrent_versions {
      transition {
        storage_class = "STANDARD_IA"
        days          = 30
      }

      expiration {
        days = 90
      }
    }
  }

  acl = "private"
  versioning {
    enabled = true
  }
}

# Enable the bucket's valid ACLs and versioning feature
data "aws_iam_policy_document" "s3_policy" {
  statement {
    effect  = "Deny"
    actions = ["s3:DeleteObject"]
    principals {
      identifiers = ["*"]
    }
    resources = [
      "arn:aws:s3:::wellcomecollection-platform-infra/*",
    ]
    condition {
      test     = "Null"
      values   = ["false"]
    }
  }

  statement {
    effect = "Allow"
    actions = [
      "s3:PutObject",
    ]
    principals {
      identifiers = ["arn:aws:iam::123456789012:root"]
    }
    resources = ["arn:aws:s3:::wellcomecollection-platform-infra/*"]
  }
}

resource "aws_s3_bucket_policy" "cweld_collection_platform_infra" {
  bucket = aws_s3_bucket.wellcome_collection_platform_infra.id
  policy = aws_iam_policy_document.s3_policy.json
}

# Enable an S3 safeguard against accidental bucket deletion
resource "aws_s3_bucket_lifecycle_policy" "wellcome_collection_platform_infra" {
  bucket = aws_s3_bucket.wellcome_collection_platform_infra.id
  policy = data.aws_iam_policy_document.s3_policy.json
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "platform_infra" {
  bucket_prefix = "wellcomecollection-platform-infra-"
}

resource "aws_s3_bucket_ownership_controls" "example" {
    bucket = aws_s3_bucket.platform_infra.id
    rule {
        object_ownership = "BucketOwnerPreferred"
    }
}

resource "aws_s3_bucket_acl" "platform_infra" {
  depends_on = [ aws_s3_bucket_ownership_controls.example ]

  bucket = aws_s3_bucket.platform_infra.id
  acl    = "private"
}

resource "aws_s3_bucket_lifecycle_configuration" "platform_infra" {
  bucket = aws_s3_bucket.platform_infra.id

  rule {
    id = "tmp"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }

    status = "Enabled"
  }

  rule {
    id = "expire_old_versions"

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }

    status = "Enabled"
  }
}

resource "aws_s3_bucket_versioning" "platform_infra" {
