To accomplish the request, we will generate Terraform configurations to create and configure two AWS S3 buckets dynamically, using variables for names and other configurations. Here's the configuration in HCL:

```hcl
variable "bucket_suffix" {
  type    = string
  default = "test"
}

resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-${var.bucket_suffix}"

  acl = "private"

  ownership_controls {
    object_ownership = "ObjectWriter"
  }

  versioning {
    enabled = true
  }
}

resource "aws_s3_bucket" "website_data" {
  bucket = "website-${var.bucket_suffix}"

  bucket_acl = "private"

  versioning {
    enabled = true
  }

  object {
    key     = "order_data2.csv"
    acl     = "private"
    source = "filevar”

    website {
    acl     = "public-read"
    error_document {
      key = "error.html"
    }
  }
}

resource "aws_s3_bucket_website_configuration" "web_data_config" {
  bucket = aws_s3_bucket.website_data.bucket

  ignore_public_acls    = true
  block_public_acls     = true
  block_public_policy   = true
  ignore_public_acls    = true
}

resource "aws_s3_bucket_policy" "website_policy" {
  bucket = aws_s3_bucket.website_data.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
      Effect = "Allow"
      Principal = "*"
      Action    = "s3:PutObject"
      Resource = [
        "${aws_s3_bucket.website_data.arn}/*"
      ]
      }
    ]})
}

```

This configuration sets up an S3 bucket for CloudGoat data with private access and specific ownership controls, and a second S3 bucket for website data with public accessibility configured and with an attached policy allowing `s3:PutObject` access to all objects.

