Below is the Terraform configuration for setting up a VPC with private subnets and launching two Amazon Linux 2 EC2 instances, attaching a shared EFS filesystem to both:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.example.id
  cidr_block         = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "PrivateSubnet1"
  }
}

resource "aws_subnet" "private2" {
  vpc_id            = aws_vpc.example.id
  cidr_block         = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "PrivateSubnet2"
  }
}

resource "aws_efs_file_system" "example" {
  creation_token = aws_iam_instance_profile.my_profile.name
}

resource "aws_iam_instance_profile" "my_profile" {
  name = "my-efs-instance-profile"
  role = aws_iam_role.my_role.name
}

resource "aws_iam_role" "my_role" {
  name = "my-efs-role"
  assume_role_policy {
    policy = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Effect = "Allow"
          Action = "sts:AssumeRole"
          Principal = {
            Service = "ec2.amazonaws.com"
          }
        },
      ]
    })
  }
}

resource "aws_instance" "ec2_instance1" {
  ami                   = data.aws_ami.amazonlinux2.id
  instance_type         = "t3.micro"
  subnet_id            = aws_subnet.private.id
  vpc_security_group_ids = [aws_security_group.private.id]
  iam_instance_profile = aws_iam_instance_profile.my_profile.name
  root_block_device {
    volume_type = "gp2"
    volume_size = 20
  }
  tags = {
    Name = "EC2Instance1"
  }
}

resource "aws_instance" "ec2_instance2" {
  ami                  = data.aws_ami.amazonlinux2.id
  instance_type        = "t3.micro"
  subnet_id           = aws_subnet.private2.id
  vpc_security_group_ids = [aws_security_group.private.id]
  root_block_device = {
    volume_type = "gp2"
    volume_size  = 20
  }
  tags = {
    Name = "EC2Instance2"
  }
}

resource "aws_security_group" "private" {
  vpc_id            = aws_vpc.example.id
  ingress {
    description = "SSH"
    from_port    = 22
    to_port      = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }
  egress {
    description = "Allow All Out"
    from_port        = 0
    to_port          = 0
    protocol        = "-1"
    cidr_blocks     = ["0.0.0.0/0"]
  }
  tags = {
    Name = "Private Security Group"
  }
}

resource "aws_instance" "ec2_instance1" {
  ami                   = data.aws_ami.amazonlinux2.id
  instance_type         = "t3.micro"
  subnet_id            = aws_subnet.private.id
  vpc_security_group_id = aws_security_group.private.id
  ebs_block_device {
    volume_type = "gp2"
    volume_size  = 20
  }
  source_dest_check = false
  tags = {
    Name = "EC2Instance1"
  }
}

resource "aws_instance" "ec2_instance2" {
  ami                  = data.aws_ami.amazonlinux2.id
  instance_type       = "t3.micro"
  subnet_id            = aws_subnet.private2.id
  vpc_security_group_id = aws_security_group.private.id
  ebs_block_device = {
    volume_type = "gp2"
    volume_size = 20
  }
  source_dest_check = false
  tags = {
    Name = "EC2Instance2"
  }
}

resource "aws_efs_mount_target" "efs_mount1" {
  file_system_id  = aws_efs_file_system.example.id
  subnet_id       = aws_subnet.private.id
  security_groups = [aws_security_group.private.id]
  dns_name        = aws_instance.ec2_instance1.private_dns
  lifecycle {
    ignore_changes = [dns_name]
  }
}

resource "aws_efs_mount_target" "efs_mount2" {
  file_system_id  = aws_efs_file_system.example.id
  subnet_id       = aws_subnet.private2.id
  security_groups = [aws_security_group.private.id]
  dns_name        = aws_instance.ec2_instance2.private_dns
  lifecycle {
    ignore_changes = [dns_name]
  }
}
```

This configuration concludes the setup of a VPC with private subnets, two EC2 instances within different availability zones within the VPC, and a shared EFS filesystem mounted on both instances. Adjust the CIDR blocks, AMI IDs, and security group settings as necessary for your specific use case.

