To set up an AWS ElastiCache Redis server instance using Terraform, you'll need to define the necessary resources including the Redis cluster configuration, parameter group, and subnet group, along with generating random IDs or passwords for security purposes. Below is the Terraform configuration as requested:

```hcl
resource "aws_elasticache_subnet_group" "redis_subnet_group" {
  subnet_ids = [aws_subnet.example.id]
}

resource "aws_elasticache_parameter_group" "redis_parameter_group" {
  family   = "redis6.x"
  parameters = {
    "maxmemory-policy" = {
      "name"  = "maxmemory-policy"
      "value" = "allkeys-lru"
      "apply_method" = "immediate"
    }
  }
}

resource "random_string" "redis_suffix" {
  length  = 5
}

resource "random_password" "password" {
  length  = 16
  special = false
}

resource "aws_elasticache_cluster" "redis_cluster" {
  availability_zones = ["us-west-2a", "us-west-2b"]
  cluster_id          = "redis-cache-${random_string.redis_suffix.result}"
  node_type           = "cache.t3.micro"
  num_cache_nodes     = 1
  subnet_group_name   = aws_elasticache_subnet_group.redis_subnet_group.name
  parameter_group_name = aws_elasticache_parameter_group.redis_parameter_group.name

  security_group_ids = [aws_security_group.redis_sg.id]
}

resource "aws_security_group" "redis_sg" {
  ingress {
    from_port   = 16379
    to_port     = 16379
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
```

This configuration sets up a Redis server in Amazon ElastiCache with a cluster and security group defining necessary parameters like `maxmemory-policy`, and uses random IDs for safe naming. It also specifies a subnet for the cache nodes and defines ingress and egress security rules to allow appropriate connections. Modify the subnet IDs, and other necessary parameters to fit your specific environment and requirements. Adjust and expand the resource definitions to match your specific needs and ensure compliance with security guidelines.

