            Resource  = "arn:aws:iam::${var.aws_account_id}:role/${aws_iam_role.redshift_role.name}"
          },
          {
            Action   = ["redshift:*"],
            Effect   = "Allow",
            Resource = "*"
          }
        ]
    })
  ]
}

resource "aws_redshift_cluster" "example" {
  cluster_identifier     = "example-cluster"
  node_type             = "dc2.large"
  master_user           = "masteruser"
  db_name              = "exampledb"
  cluster_type          = "multi-node"
  number_of_nodes       = 2
  publicly_accessible  = false
  encrypted            = true

  iam_roles = [aws_iam_role.redshift_role.arn]
}
```

This configuration provisions an AWS IAM role suitable for transferring credentials to a Redshift cluster and attaches that role to an instance of a Redshift cluster provisioned using Terraform. Note the use of `jsonencode` within the policy block, which allows you to specify JSON policy in a dynamic way based on Terraform expressions.

