response:
To configure Terraform for invoking an `aws_lambda_function` named `test_lambda` each time a new EC2 AMI is generated, you can use the AWS Lambda functionality provided in Terraform to achieve this. Here's how you can structure the Terraform configuration using HCL:

```hcl
resource "aws_iam_role" "lambda_execution_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version: "2012-10-17",
    Statement: [
      {
        Action: "sts:AssumeRole",
        Effect: "Allow",
        Principal: {
          Service: "lambda.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_lambda_function" "test_lambda" {
  function_name = "testLambda"
  handler       = "handler_function"
  runtime       = "python3.8"
  role          = aws_iam_role.lambda_execution_role.arn
  source_code_hash = filebase64sha256("lambda_function.zip")
  filename      = "lambda_function.zip"
}

resource "aws_cloudwatch_event_rule" "ami_created" {
  name        = "ami-created"
  description = "Trigger Lambda when a new AMI is created"

  event_pattern = jsonencode({
    "source": [
      "aws.ec2"
    ],
    "detail-type": [
      "EC2 Instance State-change Notification"
    ],
    "detail": jsonencode({
      "state": "pending"
    })
  })
}

resource "aws_cloudwatch_event_target" "invoke_lambda" {
  rule = aws_cloudwatch_event_rule.ami_created.name
  arn = aws_lambda_function.test_lambda.arn
}
```

In this configuration, the Lambda function is configured with a role to execute. A CloudWatch event rule triggers lambda invocation whenever a new AMI is initiated, using event pattern matching based on EC2 state change notifications. The function target is then set up to have CloudWatch events trigger this Lambda function.

