  name           = "my-table-${random_id.suffix.hex}"
  hash_key       = "id"

  lifecycle {
    ignore_changes = ["arn"]
  }

  attribute {
    name = "id"
    type = "S"
  }

  billing_mode = "PAY_PER_REQUEST"

  replication {
    global_tables = {
      global_secondary_index = []
    }
  }

  region_config {
    us_east_1 = {
      region_name          = "us-east-1"
      min_capacity        = 3
      read_capacity       = 5
      write_capacity     = 5
    }

    us_west_1 = {
      region_name          = "us-west-1"
      min_capacity        = 3
      read_capacity       = 5
      write_capacity     = 5
    }

    us_west_2 = {
      region_name          = "us-west-2"
      min_capacity        = 3
      read_capacity       = 5
      write_capacity     = 5
    }
  }
}
```

This configuration sets up a DynamoDB table with global replication in the specified AWS regions. The `random_id` resource generates a unique suffix for the table name, ensuring no conflicts. The `region_config` block specifies the replication configurations for each region.

