  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  map_public_ip_on_launch = true
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2a"
}

data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filters = {
    name = "amzn2-ami-hvm-*-x86_64-gp2"
    root-device-type = "ebs"
  }
}

resource "aws_launch_template" "ec2_fleet" {
  name_prefix   = "example-"
  image_id      = data.aws_ami.amazon_linux.id
  instance_type = "t3.micro"

  network_interfaces {
    associate_public_ip_address = true
    subnet_id                   = aws_subnet.public.id
  }
}

resource "aws_ec2_fleet" "example_fleet" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.ec2_fleet.id
      version            = "$Latest"
    }

    overrides {
      instance_type     = "t3.micro"
      count             = 5
    }
  }

  spot_options {
    spot_max_price    = "0.05"
    instance_pools_to_use_count = 2
    allocation_strategy = "lowestPrice"
  }

  allocation_strategies {
    allocation_strategy = "lowestPrice"
    instance_pools_to_use_count = 1
  }

  target_capacity_specification {
    default_target_capacity_type = "spot"
    total_target_capacity        = 9
  }

  on_demand_target_capacity = 5
}

