response:
To provision an Amazon Managed Streaming for Kafka (MSK) cluster in AWS us-east-1 and configure it to send logs to a CloudWatch Logs group, you need to create the MSK cluster and assign logging configurations. Here's the Terraform configuration aligned with the provided formatting:

```hcl
resource "aws_msk_cluster" "test" {
  broker_node_group_info {
    broker_node_group_id = "test-msk-broker"
  }

  az_configurations {
    broker_node_group_info {
      broker_node_group_id = var.broker_node_group_id
    }

    logging_info {
      broker_logs {
        topic = "test-msk-clusterlogs"
        cloud_watch_logs {
          enabled              = true
          cloud_watch_logs_role_arn = aws_iam_role.logs.arn
          log_group_arn         = aws_cloudwatch_log_group.kafka_logs.arn
          data_retention        = 1440
          retention_in_hours   = 1
        }
      }
      maintenance_window {
        daily_start_time = "03:00"
      }
    }
  }

  client_bootstrap {
    tls {
      cert         = var.client_bootstrap_tls_cert
      private_key = var.client_bootstrap_tls_private_key
    }
  }

  configuration {
    engine_type  = "kafka"
    kafka_version = "2.6.1"
  }

  cloudwatch_encryption_in_transit {
    enabled = true
    cloud_watch_logs_encryption_config {
      cloud_watch_logs_encryption_enabled = true
      cloud_watch_logs_encryption_kms_key_id = aws_kms_key.cloudwatch_encryption.arn
    }
  }

  encryption_in_transit {
    enabled = true
    kms_key_id = aws_kms_key.encryption.arn
  }
  sasl {
    enabled = true
    sasl_scram = {
      active            = true
      skd_encryption    = true
    }
    sasl_tls {
      enabled      = true
      certificate  = var.sasl_tls_cert
    }
    security_config {
      kafka_version = "2.6.1"
      config {
        ssl = {
          enable = sasl_tls.enabled
        }
        scram = {
          enable   = true
          ca <od_cert> = concat(
          var.sasl_tls_certificate.crt)
        }
        password = sasl.scram[1,0].secret_password
      }
    }
  }
}

resource "aws_cloudwatch_log_group" "kafka_logs" {
  name = "/aws/msk/test-cluster"
}

resource "aws_iam_role" "logs" {
  assume_role_policy = jsonencode(
    {
      "Version" : "2012-10-17",
      "Statement" : [
        {
          "Effect" : "Allow",
          "Principal" : {
            "Service" : "logs.amazonaws.com"
          },
          "Action" : "sts:AssumeRole"
        }
      ]
    }
  )
  policies = [
    {
      pdf = jsonfileencode(
      Configuration: Allow all CloudWatch actions
      Version: 2012-10-17
    })
  ]
}
```

This configuration creates an MSK cluster with logging enabled. It provisions a CloudWatch Logs role and group to archive the logs. By using these resources, you ensure that logs are appropriately encrypted and managed in transit.

