Below is the Terraform configuration for provisioning an Amazon MSK cluster with encryption enabled for data at rest. This configuration uses AWS MSK resources, and configures the encryption settings.

```hcl
resource "aws_msk_cluster" "example" {
  cluster_name          = "example-cluster"
  configuration_info {
    software_version = "2.4.1"
  }
  encryption_info {
    encryption_in_transit {
      data_in_transit_encryption_options {
        encryption_mode = "active"
      }
    }
    encryption_at_rest {
      checksum_algorithm        = "crc32c"
      encryption_type = "kafka"
      kms_key_id = "arn:aws:kms:us-west-2:1234abcd-12ab-34cd-56ef-1234567890ab:key/abcd1234abcd1234-5678efgh"
    }
  }
  broker_node_group_info {
    broker_node_group_id = "broker1"
    broker_node_type   = "kafka.t3.small"
    availability_zone = "us-west-2b"
    security_groups   = ["sg-01234abcd5678efgh"]
  }
  zookeeper_node_group_info {
    node_id          = "zookeeper1"
    node_type        = "kafka.t3.medium"
    availability_zone = "us-west-2b"
    security_groups   = ["sg-01234abcd5678efgh"]
  }
}
```

This configuration sets the MSK cluster with encryption for data at rest by specifying encryption at rest details using AWS KMS. Additionally, it specifies a broker node group with a specified security group and availability zone. Note that security groups and encryption details should reflect your AWS setup and intentional cluster configurations.

