data "aws_iam_policy_document" "assume_role" {
    statement {
        effect = "Allow"
        principals {
            type = "Service"
            identifiers = ["firehose.amazonaws.com"]
        }
        actions = ["sts:AssumeRole"]
        }
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled = false
            }
            s3 {
                enabled = false
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
To provision an Amazon Managed Streaming for Kafka (MSK) cluster with both jmx_exporter and node_exporter configurations turned on, you can use the following Terraform configuration written in HCL format:

```hcl
resource "aws_msk_cluster" "example_cluster" {
  // Configure cluster with necessary parameters
  broker_security_groups = ["sg-12345678"]
  kafka_version       = "2.2.0"
  number_of_brokers   = 3
  storage_mode       = "INTERDISK"
}

resource "aws_msk_configuration" "example_config" {
  // Enable jmx_exporter
  jmx_exporter_enabled = true

  // Enable node_exporter
  node_exporter_enabled = true

  broker_node_group_counts = {
    data_plane = 3
  }
}

resource "aws_msk_broker" "example_broker" {
  msk_cluster_arn = aws_msk_cluster.example_cluster.arn

  // Assign necessary configurations
  open_wire_formats_enabled = ["JMX", "NODE"]

  // Ensure other necessary configurations are set
  security_configurations = {
    "enableTLS" = true
  }
}
```

This setup ensures both the jmx_exporter and node_exporter configurations are enabled in the MSK cluster, along with security configurations and broker node group counts necessary for Kafka brokers. Adjust the resource identifiers and parameters according to your specific requirements.

