  }
}

resource "aws_route" "first_vpc" {
  vpc_id      = aws_vpc_peering_connection.peer.vpc_id
  destination_cidr_block = aws_vpc.second_vpc.cidr_block
}

resource "aws_route" "second_vpc" {
  vpc_id      = aws_vpc_peering_connection.peer.peer_vpc_id
  destination_cidr_block = aws_vpc.first_vpc.cidr_block
}
```

These configurations establish a VPC peering connection between two VPCs and add routes to each VPC so that they can communicate with one another. It is important to note that the peering connection establishes mutual communication between two VPCs, meaning that the two VPCs can communicate directly, but not via internet-based routes such as those passing through their internet gateways.

