response:
To provide Terraform configurations for an Amazon Redshift cluster with endpoints accessible from two separate subnets, you need to create a Redshift cluster resource and configure VPC security groups to allow access from both subnets. Below is the HCL code within a Markdown code block, demonstrating how such configurations can be provisioned using Terraform with AWS:

```hcl
resource "aws_redshift_subnet_group" "example" {
  name                    = "redshift-subnet-group"
  subnet_ids              = ["subnet-abc123", "subnet-def456"]
  description            = "Redshift subnet group"
  vpc_id                 = "vpc-12345"
}

resource "aws_redshift_cluster" "example" {
  cluster_identifier       = "redshift-cluster-1"
  node_type               = "dc2.large"
  number_of_nodes         = 2
  cluster_subnet_id       = aws_redshift_subnet_group.example.id
  publicly_accessible     = true
}

resource "aws_security_group" "example" {
  name        = "redshift-example-sg"
  description = "Security group for redshift cluster"

  ingress {
    from_port       = 1
    to_port         = 5439
    protocol       = "tcp"
    cidr_blocks    = ["0.0.0.0/0"]
    description    = "Allow Redshift to receive inbound JDBC/ODBC connections."
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol   = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group_rule" "example" {
  type        = "ingress"
  from_port   = 5439
  to_port     = 5439
  protocol    = "tcp"
  source_security_group_id = aws_security_group.example.id
}

resource "aws_security_group" "example" {
  vpc_id = aws_redshift_cluster.example.vpc_security_group_id

  ingress {
    from_port   = 9646
    to_port     = 9646
    protocol   = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  ingress {
    from_port   = 1433
    to_port     = 1433
    protocol   = "tcp"
    cidr_blocks = ["10.0.1.0/24"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
```

In this configuration:

- The `aws_redshift_cluster` resource is created with a VPC security group and a subnet group composed of the required subnets for the cluster.
- The `aws_redshift_subnet_group` and `aws_security_group` resources are used to ensure endpoints can be reached in the VPC subnets from the cluster.
- Access rules are configured via `aws_security_group_rule` and `aws_security_group` to allow inbound connections from desired subnets.

This configuration allows the cluster to be accessible from the specified subnets using the security group.

