response:
To design infrastructure for a computer science course autograding system that executes student submissions hosted on GitHub within AWS, you can create a setup using AWS CodeBuild and an S3 bucket to facilitate autograding. Below is the Terraform configuration in HCL format that outlines this infrastructure:

```hcl
resource "aws_s3_bucket" "grader_reports" {
  bucket = "cs-course-grader-reports"
  acl    = "private" // Ensure privacy for students' submissions
}

resource "aws_codebuildar_project" "cs_course_autograder" {
  name          = "CSCourseAutograder"
  description   = "Automated grading system for CS course submissions"

  source {
    type            = "GITHUB"
    location        = "https://github.com/CSCourse/GradedSubmissions.git"
  }

  environment {
    type          = "LINUX_CONTAINER"
    image         = "aws/codebuild/standard:5.0"
    compute_type = "BUILD_GENERAL1_MEDIUM"
  }

  artifacts {
    type   = "NO_ARTIFACTS"
    s3_location {
      bucket_name = aws_s3_bucket.grader_reports.bucket
    }
  }
}

resource "aws_iam_role" "codebuild_role_cs" {
  name = "csCourseCodeBuildRole"

  assume_role_policy {
    statement = {
      actions = ["sts:AssumeRole"]
      principals {
        type = "Service"
      entities = ["codebuild.amazonaws.com"]
      }
    }
  }
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "csCourseCodeBuildPolicy"
  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "s3:PutObject",
        "s3:GetObject",
        "s3:ListBucket"
      ],
      "Resource": [
        "${aws_s3_bucket.grader_reports.omega}",
        "${aws_s3_bucket.grader_reports.arn}/*"
      ]
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "codebuild_attach_policy" {
  role       = aws_iam_role.codebuild_role_cs.name
  policy_arn  = aws_iam_policy.codebuild_policy.arn
}

resource "awsCodebuildSourceCredential" "codebuild_cred" {
  auth_type = "PERSONAL_ACCESS_TOKEN"
  token      = var.github_personal_access_token
}

resource "aws_codebuildar_project_source" "code_build_creds" {
  type = "GITHUB"
  credentials = aws_codebuild_source_credential.id
  owner = "csCourse"
  repo = "GradedSubmissions"
}

resource "data" "terraform_state" {
  count = 1.0
}
```

This configuration uses an S3 bucket to store grading reports, and employs AWS CodeBuild to execute student submissions from a GitHub repository. Additional resources like IAM roles and policies ensure that CodeBuild has access to the S3 bucket for storing grading output. Replace placeholders (like `var.github_personal_access_token`) with your actual credentials or variables within the Terraform setup. 

Ensure that you adjust the CodeBuild environment configuration, GitHub repository URLs, and IAM policy statements according to your specific requirements and infrastructure design.

