```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_vpc" "ospc" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "subnet" {
  vpc_id     = aws_vpc.ospc.id
  cidr_block = "10.0.1.0/24"
}

resource "aws_security_group" "codebuild" {
  name        = "codebuild_security_group"
  description = "Security group for AWS CodeBuild with no internet access"
  vpc_id      = aws_vpc.ospc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.ospc.cidr_block]
  }
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder"
  service_role  = aws_iam_role.codebuild.arn
  build_timeout = "5"
  environment {
    compute_type                = "BUILD_GENERAL1_MEDIUM"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    privileged_mode             = false
    image_pull_credentials_type = "CODEBUILD"
    environment_variable {
      name  = "GITHUB_REPO"
      value = "https://github.com/your-username/repository"
    }
    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.results.bucket
    }
  }
  source {
    type     = "GITHUB"
    location = "https://github.com/your-username/repository"
  }
  artifacts {
    type             = "S3"
    location         = aws_s3_bucket.results.bucket
    name             = "autograder_results.zip"
    packaging        = "ZIP"
  }
  vpc_config {
    subnet_ids         = [aws_subnet.subnet.id]
    security_group_ids = [aws_security_group.codebuild.id]
    // No internet/outgoing
    vpc_id             = aws_vpc.ospc.id
    // Use private DNS only, blocking any public internet access
    restrictions {
      ip_range = "10.0.0.0/16"
    }
  }
}

resource "aws_iam_role" "codebuild" {
  name = "codebuild_role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "codebuild.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "codebuild_permissions" {
  name = "codebuild_permissions"
  role = aws_iam_role.codebuild.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents",
        "s3:*"
      ],
      "Resource": "*"
    }
  ]
}
EOF
}

resource "aws_s3_bucket" "results" {
  bucket = "autograder-results"
  acl    = "private"
}

resource "aws_dynamodb_table" "queue" {
  name           = "codebuild-queue"
  billing_mode   = "PROVISIONED"
  read_capacity  = 5
  write_capacity = 5
  hash_key       = "BuildId"

  attribute {
    name = "BuildId"
    type = "S"
  }
}
```

In this Terraform configuration:
- An isolated VPC with a single subnet is set up where CodeBuild projects will run without internet access.
- An AWS CodeBuild project configured with security group restrictions to ensure that the environment has no ability to reach the internet.
- The IAM role and policy have permissions to access necessary AWS services.
- An S3 bucket is created to store the results of the builds.
- A DynamoDB table is set up to manage the CodeBuild build queue. 

The `GITHUB_REPO` environment variable should be set to the specific repository location where student submissions are hosted. 

Remember that the GitHub location, bucket names, and IAM policies must be tailored to specific project security and access requirements. Adjustments might include VPC CIDR, subneting, and access control based on organizational practices.

