Below is the Terraform configuration for designing a controlled environment for executing student submissions from GitHub using AWS services. This configuration includes necessary resources such as AWS S3, AWS CodeBuild, an AWS VPC, subnets, and security groups to ensure secure execution and grading.

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_s3_bucket" "submission_bucket" {
  bucket = "student-submissions"
}

resource "aws_vpc" "course_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet" {
  vpc_id     = aws_vpc.course_vpc.id
  cidr_block  = "10.0.1.0/24"
  availability_zone = "us-west-2a" # feel free to adjust AZ as needed
}

resource "aws_security_group" "submission_security_group" {
  vpc_id = aws_vpc.course_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.1.0/24"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_codebuild_project" "grading_project" {
  name         = "student_grading_project"
  description  = "Grading project for student submissions"
  build_spec   = "buildspec.yml"
  service_role = "arn:aws:iam::123456789012:role/service-role/aws_codebuild_project"
  source_version = "master"
  source_type    = "GITHUB"
  build_image   = "aws/codebuild/standard:4.0"
}

resource "aws_iam_role" "codebuild_role" {
  name = "CodeBuildGraders"
  assume_role_policy {
    version = "2012-10-17"
    statement = {
      effect = "Allow"
      actions = ["sts:AssumeRole"]
      principals = {
        type = "Service"
        identifiers = ["codebuild.amazonaws.com"]
      }
    }
}

resource "aws_iam_instance_profile" "codebuild_profile" {
  role = aws_iam_role.codebuild_role.name
}

resource "aws_codebuild_trigger" "trigger" {
  project_id = aws_codebuild_project.grading_project.id
  source {
    type = "GITHUB"
    owner = "self"
    repo  = "student-repo"
  }
  trigger_event = "PUSH"
  branch_filter = "^(master)$"
}

resource "aws_eip" "control_eip" {}
resource "aws_nat_gateway" "nat_gateway" {
  allocation_id = aws_eip.control_eip.id
  subnet_id = aws_subnet.subnet.id
}
```

Here, a controlled environment is established for student submissions using AWS resources. Students' code is hosted in an S3 bucket. AWS CodeBuild is configured to use the submissions for grading when changes occur on the GitHub branch, ensuring no outbound internet access with security groups. An AWS Bitbucket in-chain trigger could further be implemented for automatic builds and tests.

