  }

  health_check {
    target             = "HTTP:8080/"
    interval          = 30
    timeout          = 5
    healthy_threshold = 2
    unhealthy_threshold = 2
    }
}

resource "aws_autoscaling_group" "video_streaming_servers" {
  name                 = "video-streaming-servers"
  min_size             = 1
  max_size             = 3
  desired_capacity     = 2
  launch_configuration = aws_launch_configuration.video_streaming.id

  vpc_zone_identifier = ["subnet-12345678", "subnet-87654321"] // Replace with your actual subnet IDs
}

resource "aws_autoscaling_attachment" "video_streaming_elb_attachment" {
