To address the request, you need to create a Terraform configuration that provisions AWS infrastructure including a primary VPC, subnets in separate availability zones, and a security group that permits database traffic. Then, deploy a publicly accessible MySQL RDS instance associated with the created subnets and security group. Here's the configuration to achieve this:

```hcl
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.main.id
  cidr_block         = "10.0.1.0/24"
  availability_zone  = "us-east-1a"
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block         = "10.0.2.0/24"
  availability_zone  = "us-east-1b"
}

resource "aws_security_group" "db" {
  name   = "db-security-group"
  vpc_id = aws_vpc.main.id

  ingress {
    description = "Allow MySQL/Aurora traffic"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_instance" "default" {
  identifier          = "my-rds-instance"
  allocated_storage   = 20
  engine              = "mysql"
  instance_class      = "db.t2.micro"
  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_groups = [aws_security_group.db.id]
  skip_final_snapshot = true
  publicly_accessible = true
}

resource "aws_db_subnet_group" "main" {
  name        = "main-subnet-group"
  db_subnet_ids = [aws_subnet.public.id, aws_subnet.private.id]
  subnet_ids     = [aws_subnet.public.id, aws_subnet.private.id]
}

output "rds_endpoint" {
  value = aws_db_instance.default.endpoint
}
```

This configuration includes:
- An AWS VPC with a CIDR block.
- Two subnets within the VPC, each in a separate availability zone.
- A security group allowing inbound MySQL database traffic.
- The RDS instance itself, which is public, associated with the created subnets and security group.
- An output specifying the RDS database endpoint for external connection use. 

Make sure that these resources and values are adjusted according to any specific requirements or preferences related to your actual project and AWS resources.

