To address your request, we will provision an AWS PostgreSQL database instance within a custom Virtual Private Cloud (VPC) and subnet, implementing specific settings such as permitting major version upgrades, auto-applying minor version updates, and keeping the instance private. Here's how the Terraform configuration would look, using the HCL (HashiCorp Configuration Language) in a single code block format:

```hcl
resource "random_id" "suffix" {
  byte_length = 8
}

resource "random_password" "db" {
  length = 16
  special = false
}

resource "aws_vpc" "example_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "example_subnet" {
  vpc_id     = aws_vpc.example_vpc.id
  cidr_block  = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_db_instance" "example_postgres" {
  identifier                     = "postgres-db-${random_id.suffix.hex}"
  instance_class                = "db.m5.large"
  allocated_storage             = 20
  engine                      = "postgres"
  engine_version              = "12.5"
  allow_major_version_upgrade = true
  apply_immediately          = true
  auto_minor_version_upgrade = true
  storage_type               = "io1"

  vpc_security_group_ids = [aws_security_group.example.id]

  subnet_name = aws_subnet.example_subnet.id
  username   = "admin"
  password   = random_password.db.result
  publicly_accessible  = false
}

resource "aws_security_group" "example" {
  vpc_id = aws_vpc.example_vpc.id

  ingress {
    cidr_blocks = ["10.0.0.0/16"]
    description = "Allow internal traffic"
    from_port   = 5432
    to_port     = 5432
    protocol   = "tcp"
  }

  egress {
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow outgoing traffic"
    from_port   = 5432
    to_port     = 5432
    protocol   = "tcp"
  }
}
```

This configuration sets up a custom RDS Subnet Group and VPC, with specified security group settings that allow internal access to the PostgreSQL instance. The configuration also implements a randomly generated identifier and passwords for enhanced security. It specifies the PostgreSQL version, enables automatic minor version updates, and permits major version upgrades during lifecycle for more flexibility in database version management.

