response:
To provision an Amazon Aurora MySQL RDS cluster along with an RDS Proxy on AWS, and configure the necessary supporting infrastructure such as a VPC, subnets, security groups, IAM roles, and utilize AWS Secrets Manager for securely storing database credentials, you can use the following Terraform configuration code in HCL format:

```hcl
resource "random_id" "suffix" {
  byte_length = 8
}

resource "random_password" "db" {
  length  = 16
  special = false
}

resource "aws_vpc" "example_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_security_group" "rds" {
  name        = "rds-cluster-sg"
  description = "Security group for the RDS cluster"
  vpc_id      = aws_vpc.example_vpc.id
}

resource "aws_security_group" "rds_proxy" {
  name        = "rds-proxy-sg"
  description = "Security group for the RDS Proxy"

  ingress {
    from_port   = 1433
    to_port     = 1433
    protocol    = "tcp"
    self         = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_rds_cluster" "example" {
  cluster_identifier = "aurora-cluster-${random_id.suffix.hex}"
  database_name      = "mydbname"
  engine            = "aurora-mysql"
  engine_version   = "5.7"
  db_subnet_group_name = aws_db_subnet_group.example.id
  security_group_ids = [aws_security_group.rds.id]
  master_username  = "masteruser"
  master_password  = aws_secretsmanager_secret_version.example.secret_string
}

resource "aws_db_subnet_group" "example" {
  name       = "subnet-group-${random_id.suffix.hex}"
  subnet_ids = ["${aws_vpc.example_vpc.main["id"]}", "${aws_vpc.example_vpc.secondary["id"]}"]
  vpc_id     = aws_vpc.example_vpc.id
}

resource "aws_rds_cluster_parameter_group" "example" {
  cluster_family = "aurora-mysql"
  parameters = {
    "binlog_format" = "ROW",
    "binlog_checksum" = "NONE",
    "version" = "5.7.10"
  }
}

resource "aws_rds_cluster_parameter" "example" {
  cluster_identifier    = aws_rds_cluster.example.cluster_identifier
  parameter            = "binlog_checksum"
  apply_method        = "pending-only"
  value               = "NONE"
  description         = "Specify binlog checksum mode"
}

resource "aws_secretsmanager_secret_version" "example" {
  secret_id     = aws_secretsmanager_secret.example.id
  secret_string = random_password.db.result
}

resource "aws_rds_proxy" "example_proxy" {
  db_cluster_identifier = aws_rds_cluster.example.id
  db_cluster_parameter_group = aws_rds_cluster_parameter_group.example.id
  vpc_security_group_ids = [aws_security_group.rds_proxy.id]
  idle_connection_timeout = 1800
  debug                 = false
  secrets             = aws_secretsmanager_secret_example.secret_arn
}

resource "aws_iam_role" "rds_role" {
  name = "rds-${random_id.suffix.hex}"
  assume_role_policy = {
    Version = "2012-10-17"
    Statement = {
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "rds.amazonaws.com"
      }
    }
  }
}
```

This configuration covers:
- The RDS cluster setup with parameters for a new VPC and attached subnet groups.
- Creating security groups for the RDS cluster and proxy.
- IAM roles for RDS access.
- Use of AWS Secrets Manager for securely managing database credentials, with RDS Proxy setup for connection pooling.
- Configuring the cluster parameter group and RDS cluster parameters.
- A proxy parameter with idle connection timeout and disabled debug logging settings.

