resource "aws_dlm_lifecycle_policy" "example" {
  description        = "Glacier lifecycle policy"
  execution_role_arn = "arn:aws:iam::123456789012:role/AWSDataLifecycleManagerDefaultRole"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "DLM to S3 Glacier"
      tags_to_apply = {
        "DLM-Date" = "true"
      }

      creation_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["00:00"]
      }

      transition {
        storage_class = "GLACIER"
        times         = ["2160"] // 60 days in hours
      }

      retention {
        retain_until_date = "2099-12-31T23:59:59Z"
      }

      copy_tags = false
    }
  }
}

