    lifecycle_rule {
      enabled = true
      prefix  = "uploads/"
      noncurrent_version_expiration = {
      days                          = 90
    }
    current_version_expiration     = {
      days                          = 365
    }
    }

    event = ["s3:ObjectCreated:*"]

    filter {
      prefix = "uploads/"
    }

    destination {
      bucket {
        name = aws_s3_bucket.glacier_vault.id
