provider "aws" {
  region = "us-west-1"
}

resource "aws_elb" "my_load_balancer" {
  name               = "my-load-balancer"
  availability_zones = ["us-west-1a", "us-west-1b"]

  listener {
    instance_port     = 80
    instance_protocol = "http"
    lb_port           = 80
    lb_protocol       = "http"
  }

  instances           = ["${aws_instance.web.id}"]
  health_check {
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 3
    interval           = 30
    target             = "HTTP:80/"
  }

  cross_zone_load_balancing = true

  subnets = ["${aws_eip.example.id}", "${aws_eip.replica.id}"]

  load_balancer_http_accounts = ["${aws_lb_vip.http.id}"]
  load_balancer_https_accounts = ["${aws_lb_vip. https id}"]
}

resource "aws_eip" "example" {
  vpc = true
}

resource "aws_eip" "replica" {
  vpc = true
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = "${aws_elb.my_load_balancer.id}"
  port               = 80
  protocol           = "HTTP"

  default_action {
    type = "forward"
    target_group_arn = aws_lb_target_group.example.id
  }
}

resource "aws_lb_listener" "https" {
  load_balancer_arn = "${aws_lb_listener.my_load_balancer.http.id}"
  port               = 443
  protocol           = "HTTPS"

  ssl_policy        = "ELBSecurityPolicy-TLS-1-2-2021-06"
