resource "aws_lb" "example" {
  name               = "example-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.example.id]
  subnets            = data.aws_subnet_ids.example.ids

  enable_deletion_protection = false

  access_logs {
    bucket  = aws_s3_bucket.lb_logs.bucket
    enabled = true
  }

  default_action {
    type             = "authenticate-cognito"
    authenticate_cognito {
      user_pool_arn       = aws_cognito_user_pool.example.arn
      user_pool_client_id = aws_cognito_user_pool_client.example.id
      user_group          = "authenticated"
      scope               = "email"
      session_cookie_name = "authSession"
      session_timeout     = 4200
    }
    type             = "forward"
    target_group_arn = aws_lb_target_group.example.arn
  }

}

resource "aws_security_group" "example" {
  name        = "example-lb-sg"
  description = "Allow all inbound traffic"
  vpc_id      = data.aws_vpc.selected.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

