Here is the Terraform configuration for creating an AWS load balancer configured with an IP-based target group:

```hcl
resource "aws_lb" "example" {
  name                 = "example-lb"
  load_balancer_type   = "network"
  subnets              = ["subnet-12345678"] // Replace with your subnet IDs
}

resource "aws_lb_target_group" "example" {
  name        = "example-lb-tg"
  protocol   = "HTTP"
  port       = 80
  vpc_id     = aws_vpc.example.id // Replace with your VPC ID
}

resource "aws_lb_target_group_attachment" "example_attach" {
  target_group_arn = aws_lb_target_group.example.arn
  target_id        = "ip-address-of-instance" // Replace with the actual IP address of the instance
  port            = 80
}
```

Note: Ensure to replace placeholders with actual values corresponding to your AWS infrastructure.

