resource "aws_vpc_peering_connection" "pike" {
  vpc_id      = aws_vpc.base.id
  peer_vpc_id = aws_vpc.peer.id
  auto_accept = true

  tags = {
    Name = "pike"
    Role = "permissions"
  }
}

resource "aws_vpc_peering_connection_accepter" "base_accepter" {
  provider                  = aws
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
  auto_accept               = true
}

resource "aws_route" "peer_to_base" {
  route_table_id            = aws_vpc.peer.main_route_table_id
  destination_cidr_block    = aws_vpc.base.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
}

resource "aws_route" "base_to_peer" {
  route_table_id            = aws_vpc.base.main_route_table_id
  destination_cidr_block    = aws_vpc.peer.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
}
```

This Terraform script sets up two VPCs (`peer` and `base`) and creates a VPC peering connection between them called `pike`. The connection includes the relevant routes to facilitate private communication as if they were on a single network, and it includes the specified tag for governance policy.

